import SwiftUI

// MARK: - PersistentToolbar

/// Fixed toolbar overlaid on the NavigationStack so it persists across root view modes
/// (timeline, rings, map) without participating in navigation transitions.
///
/// - Leading button: toggles map on/off.
/// - Center button:  glyph + SVNR label; toggles timeline/rings on list modes.
/// - Trailing button: opens camera.
struct PersistentToolbar: View {
    @Binding var viewMode: MainViewMode
    let onMapAction: () -> Void
    /// Toggles timeline/rings when on a list mode; returns to list when on map.
    let onCenterAction: () -> Void
    let onCameraAction: () -> Void

    @Environment(\.horizontalSizeClass) private var sizeClass

    private var horizontalPadding: CGFloat {
        sizeClass == .regular ? DesignTokens.Spacing.extraLarge : DesignTokens.Spacing.medium
    }

    var body: some View {
        HStack(spacing: 0) {
            // Leading: map toggle
            Button(action: onMapAction) {
                Image(systemName: viewMode == .map ? "list.bullet" : "map")
                    .font(.title3)
                    .svnrSymbolPalette()
                    .frame(width: 44, height: 44)
            }
            .buttonStyle(.plain)

            Spacer()

            // Center: glyph + wordmark — tints accent in rings mode
            Button(action: onCenterAction) {
                HStack(spacing: 5) {
                    Image("svnr-glyph-fill")
                        .resizable()
                        .scaledToFit()
                        .frame(width: 22, height: 22)
                        .foregroundStyle(viewMode == .rings ? Color.accent : Color.primary)
                    Text("SVNR")
                        .font(.headline.weight(.heavy).design(.rounded))
                        .foregroundStyle(viewMode == .rings ? Color.accent : Color.primary)
                }
            }
            .buttonStyle(.plain)

            Spacer()

            // Trailing: camera
            Button(action: onCameraAction) {
                Image(systemName: "camera")
                    .font(.title3)
                    .svnrSymbolPalette()
                    .frame(width: 44, height: 44)
            }
            .buttonStyle(.plain)
        }
        .frame(height: 44)
        .padding(.horizontal, horizontalPadding)
        .frame(maxWidth: .infinity)
        .background(.ultraThinMaterial)
        .overlay(
            Rectangle()
                .strokeBorder(Color(uiColor: .separator).opacity(0.5), lineWidth: 0.5)
        )
        .shadow(color: Color.black.opacity(0.18), radius: 12, x: 0, y: 4)
    }
}

