import Foundation

/// Type-safe routes for app navigation.
enum Route: Hashable {
    case souvenirList
    case souvenirNew
    case souvenir(id: UUID)
    case souvenirPhoto(souvenirID: UUID, photoID: UUID)
    case friendMap
    case friendMapFocused(souvenirID: UUID, islandState: ContactIslandState = .fullSheet)  // Navigate to map centered on specific souvenir
    case friendMapAtLocation(souvenirID: UUID, latitude: Double, longitude: Double)  // Navigate to map at specific coordinates
    case friendMapFromFocus(souvenirID: UUID, latitude: Double, longitude: Double)  // Navigate to map from focus view, centers and dismisses focus
    case contactNew
    case contactRings(contactID: UUID)  // View contact's rings (inner circles)
    case contactRingAssignment(contactID: UUID)  // Assign contact to a ring
    case devTools
    case settings
}

