//
//  UtilitiesDetentCalculator.swift
//  souvenir
//
//  Memoized detent calculator to prevent Observable churn in ContactIsland.
//  This class solves the corner loop caused by GeometryReader.onChange firing
//  continuously, which recalculates detent properties, creating new object
//  identities, triggering Observable updates, and causing _UICornerProvider loop.

import SwiftUI

/// Calculates and memoizes PresentationDetent objects for ContactIsland.
///
/// **Problem Being Solved:**
/// GeometryReader.onChange fires on every frame → computed detent properties recalculate
/// → new PresentationDetent objects created (different identity) → Observable publishes
/// → _UICornerProvider loop (system corner radius provider enters infinite loop).
///
/// **Solution:**
/// Memoize (cache) detent height calculations by screen height. Return PresentationDetent
/// values built from the same cached CGFloat heights on every call. This breaks the
/// value-identity churn that drives the Observable loop.
///
/// **Caching Strategy:**
/// - Keyed by: `screenHeight` (rounded to nearest integer to reduce cache pollution)
/// - Cached: tuple of (compact, fullSheet) CGFloat heights — NOT PresentationDetent
/// - Reason: In iOS 26+, PresentationDetent's internal storage has @MainActor deallocation
///   requirements. Storing PresentationDetent in a class property triggers
///   swift_task_deinitOnExecutorImpl on dealloc, which crashes in test environments.
///   Caching CGFloat avoids this entirely — same height arithmetic, safe storage.
/// - Thread safety: not required (always called from main thread via @State)
///
final class DetentCalculator {
    /// Cache of height triples keyed by screen height (rounded to integer).
    /// Stores CGFloat rather than PresentationDetent to avoid actor-isolation
    /// issues with PresentationDetent's internal storage on iOS 26+.
    private var heightCache: [Int: (compact: CGFloat, fullSheet: CGFloat)] = [:]

    /// Round screen height to reduce cache fragmentation.
    /// Small fluctuations (sub-pixel jitter from GeometryReader) shouldn't create new entries.
    /// Rounding to integer means ~1pt changes don't fragment the cache.
    private func cacheKey(for screenHeight: CGFloat) -> Int {
        Int(screenHeight.rounded())
    }

    /// Get or create detent objects for the given screen height.
    ///
    /// Heights are memoized so the same arithmetic isn't repeated for identical
    /// (or very similar) screen heights, preventing Observable churn in ContactIsland.
    ///
    /// - Parameter screenHeight: The current screen height in points
    /// - Returns: Tuple of (compact, fullSheet) PresentationDetent objects
    func detents(for screenHeight: CGFloat) -> (compact: PresentationDetent, fullSheet: PresentationDetent) {
        let key = cacheKey(for: screenHeight)

        let heights: (compact: CGFloat, fullSheet: CGFloat)
        if let cached = heightCache[key] {
            heights = cached
        } else {
            heights = calculateHeights(for: screenHeight)
            heightCache[key] = heights
        }

        return (
            compact: .height(heights.compact),
            fullSheet: .height(heights.fullSheet)
        )
    }

    /// Calculate raw height values based on screen height and design tokens.
    ///
    /// - Parameter screenHeight: The current screen height in points
    /// - Returns: Tuple of (compact, fullSheet) CGFloat heights
    private func calculateHeights(for screenHeight: CGFloat) -> (compact: CGFloat, fullSheet: CGFloat) {
        let compactHeight = DesignTokens.ContactIsland.compactHeight

        // If screen height is invalid, return safe defaults
        guard screenHeight > 0 else {
            return (
                compact: compactHeight,
                fullSheet: DesignTokens.ContactIsland.fullSheetHeight
            )
        }

        // Calculate fullSheet height based on screen height
        let fullSheetHeight = screenHeight * ContactIslandState.fullSheetMaxRatio

        return (compact: compactHeight, fullSheet: fullSheetHeight)
    }

    /// Clear the cache (useful for testing or memory pressure)
    func clearCache() {
        heightCache.removeAll()
    }

    /// Return cache statistics (for debugging/monitoring)
    func cacheStats() -> (hitRate: Double, entries: Int, estimatedSize: Int) {
        let entries = heightCache.count
        // Estimate: Int key (8 bytes) + 3 CGFloat values (8 bytes each) = 32 bytes per entry
        let estimatedBytesPerEntry = 8 + 24
        let estimatedSize = estimatedBytesPerEntry * entries

        return (hitRate: 0.0, entries: entries, estimatedSize: estimatedSize)
    }
}

