            // Sheets stay translucent only when the system background is cleared and we supply material via the presentation background.
            .background(Color.clear)
            .background {
                FullScreenMetricsReader { newHeight, newInsets in
                    let newKey = Int(newHeight.rounded())
                    let currentKey = Int(screenHeight.rounded())
                    guard newKey > 0 else { return }
                    guard newKey != currentKey || newInsets != safeAreaInsets else { return }
                    DispatchQueue.main.async {
