    @ViewBuilder
    private func applySearchBehavior<Content: View>(to content: Content, usesSearchable: Bool = true) -> some View {
        if isSearchVisible, usesSearchable {
            NavigationStack {
                content
                    .searchable(
                        text: $nameText,
                        placement: .navigationBarDrawer(displayMode: .always),
                        prompt: Text(namePlaceholder)
