    private func startNameEditing() {
        isEditingName = true
        hasConfirmedSelection = false
        searchResults = []
        hasEditedName = false
        // Allow blur so tapping away can commit/cancel edits (handled in isSearchFocused onChange).
        allowSearchBlur = true
        let displayName = contactDisplayName.trimmingCharacters(in: .whitespacesAndNewlines)
        let actualName = placeholderNames.contains(displayName) ? "" : displayName
        originalNameText = actualName
        nameText = actualName
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.05) {
            isSearchFocused = true
        }
    }

    private func clearNameTextIfPlaceholder() {
        let trimmed = nameText.trimmingCharacters(in: .whitespacesAndNewlines)
        if placeholderNames.contains(trimmed) {
            nameText = ""
        }
    }

    private func finishNameEditing() {
        let trimmed = nameText.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmed.isEmpty {
            updateContactName(with: trimmed)
        } else {
            nameText = originalNameText
        }
        isEditingName = false
        searchResults = []
        allowSearchBlur = true
        isSearchFocused = false
        hasConfirmedSelection = !trimmed.isEmpty
        hasEditedName = false
        expandToFullSheetIfNeeded()
    }

    private func cancelNameEditing() {
        nameText = originalNameText
        isEditingName = false
        searchResults = []
        allowSearchBlur = true
        isSearchFocused = false
        hasEditedName = false
        expandToFullSheetIfNeeded()
    }

