    private func copyHomeAddressToClipboard() {
        let address = souvenir.primaryContact?.address ?? ""
        guard !address.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
        UIPasteboard.general.string = address
        UIImpactFeedbackGenerator(style: .light).impactOccurred()
    }

    private func handleHomeAction() {
        let address = (souvenir.primaryContact?.address ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !address.isEmpty else { return }
        let souvenirID = souvenir.id

        copyHomeAddressToClipboard()
        showHomeCopiedToastForAMoment()

        // Navigate the map to the contact's home address.
        homeGeocodeTask?.cancel()
        homeGeocodeTask = Task {
            let coordinate = await geocodeAddress(address)
            guard !Task.isCancelled, let coordinate else { return }
            await MainActor.run {
                NotificationCenter.default.post(
                    name: .svnrFocusMapOnSouvenir,
                    object: nil,
                    userInfo: [
                        "souvenirID": souvenirID,
                        "latitude": coordinate.latitude,
                        "longitude": coordinate.longitude
                    ]
                )
            }
        }
    }

    private func showHomeCopiedToastForAMoment() {
        homeToastTask?.cancel()
        withAnimation(.easeInOut(duration: 0.15)) {
            showHomeCopiedToast = true
        }
        homeToastTask = Task { @MainActor in
            try? await Task.sleep(for: .milliseconds(1100))
            withAnimation(.easeInOut(duration: 0.2)) {
                showHomeCopiedToast = false
            }
        }
    }

	    private func geocodeAddress(_ address: String) async -> CLLocationCoordinate2D? {
	        do {
	            let request = MKLocalSearch.Request()
	            request.naturalLanguageQuery = address
	            request.resultTypes = [.address]

	            let search = MKLocalSearch(request: request)
	            let response = try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<MKLocalSearch.Response?, Error>) in
	                search.start { response, error in
	                    if let error {
	                        continuation.resume(throwing: error)
	                        return
	                    }
	                    continuation.resume(returning: response)
	                }
	            }

	            if #available(iOS 26.0, *) {
	                return response?.mapItems.first?.location.coordinate
	            } else {
	                return response?.mapItems.first?.placemark.coordinate
	            }
	        } catch {
	            print("⚠️ [Home] local search failed: \(error)")
	            return nil
	        }
	    }

