    // MARK: - Gestures
    private func handleHorizontalSwipe(direction: Int) {
        guard souvenirs.count > 1 else { return }
        let nextIndex: Int
        if direction > 0 {
            nextIndex = (currentSouvenirIndex + 1) % souvenirs.count
        } else {
            nextIndex = (currentSouvenirIndex - 1 + souvenirs.count) % souvenirs.count
        }
        withAnimation(ContactIslandAnimation.quickSpring) {
            currentSouvenirIndex = nextIndex
        }
    }

