    private var birthtimeWheelBinding: Binding<Date> {
        Binding(
            get: { souvenir.primaryContact?.birthday ?? Date() },
            set: { newTime in
                guard let contact = souvenir.primaryContact else { return }
                let calendar = Calendar.current
                let existing = contact.birthday ?? Date()
                let date = calendar.dateComponents([.year, .month, .day], from: existing)
                let time = calendar.dateComponents([.hour, .minute], from: newTime)
                var merged = date
                merged.hour = time.hour
                merged.minute = time.minute
                let updated = calendar.date(from: merged) ?? newTime
                updateContactBirthday(updated)
            }
        )
    }

