///
///  ViewsContactIsland.swift
///  souvenir
///
///  Find My-style floating drawer with three springy states
///

import SwiftUI
import CoreData
import Contacts
import CoreLocation
import UIKit
import MapKit

struct ContactIsland: View {
    @ObservedObject var souvenir: SouvenirEntity
    @Binding var currentSouvenirIndex: Int
    let souvenirs: [SouvenirEntity]
    var currentPhotoIndex: Int = 0
    var isOnboarding: Bool = false
    var isNewSouvenirFlow: Bool = false
    var initialState: ContactIslandState = .compact
    /// Binding for external state control (e.g., from map view)
    var externalState: Binding<ContactIslandState>?
    var onDismiss: (() -> Void)?
    /// Called when user taps save in onboarding mode
    var onSave: (() -> Void)?
    /// Called when island state changes (for parent coordination)
    var onStateChange: ((ContactIslandState) -> Void)?
    /// Called when user swipes up from fullSheet state (to navigate to souvenir detail)
    var onSwipeUpFromFullSheet: (() -> Void)?
    var isPreviewInline: Bool = false

    @Environment(\.managedObjectContext) private var viewContext
    @Environment(\.verticalSizeClass) private var verticalSizeClass
    @Environment(\.horizontalSizeClass) private var horizontalSizeClass

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: .default
    )
    private var selfContacts: FetchedResults<ContactEntity>

    @StateObject private var locationService = LocationService()
    @State private var screenHeight: CGFloat = 0
    @State private var safeAreaInsets: UIEdgeInsets = .zero
    @State private var isDetentAnimating = false
    @State private var islandState: ContactIslandState = .compact
    /// Memoizes detent calculations to prevent Observable churn from GeometryReader.onChange firing.
