    /// All `.onChange`, `.onAppear`, and `.onReceive` modifiers grouped into two
    /// helpers so the compiler does not have to type-check the entire chain at once.
    private func lifecycleModifiers<V: View>(_ view: V) -> some View {
        lifecycleModifiersB(lifecycleModifiersA(view))
    }

    /// First half: data-driven `.onChange` modifiers.
    private func lifecycleModifiersA<V: View>(_ view: V) -> some View {
        view
            .onChange(of: contactDisplayName) { _, newValue in
                if !isEditingName {
                    nameText = newValue
                }
                expandToFullSheetIfNeeded()
            }
            .onChange(of: currentPhoto?.locationString ?? "") { _, _ in
                syncMeetPlaceFromPhotoIfNeeded()
            }
            .onChange(of: searchResults.count) { _, newCount in
                guard isOnboarding, isEditingName, isSearchFocused else { return }
                guard !nameText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
                guard newCount > 0 else { return }
                guard islandState != .fullSheet else { return }
                withAnimation(ContactIslandAnimation.spring) {
                    islandState = .fullSheet
                }
            }
            .onChange(of: isSearchFocused) { _, isFocused in
                if !isFocused {
                    // When editing, blurring should behave like tapping the trailing save/cancel button.
                    if isEditingName {
                        if shouldShowConfirmButton {
                            finishNameEditing()
                        } else {
                            cancelNameEditing()
                        }
                        return
                    }

                    if !allowSearchBlur {
                        isSearchFocused = true
                        return
                    }
                    allowSearchBlur = false
                    return
                }

                guard islandState != .fullSheet else { return }
                withAnimation(ContactIslandAnimation.spring) {
                    islandState = .fullSheet
                }
            }
    }

    /// Second half: appearance, notification, and state-sync modifiers.
    private func lifecycleModifiersB<V: View>(_ view: V) -> some View {
        view
            .onAppear {
                handleOnAppear()
            }
            .onReceive(NotificationCenter.default.publisher(for: .svnrFocusMeetTime)) { notification in
                guard let targetID = notification.userInfo?["souvenirID"] as? UUID else { return }
                guard targetID == souvenir.id else { return }
                openMeetTimePicker()
            }
            .onChange(of: externalState?.wrappedValue) { _, newState in
                print("🏝️ [ExternalState] -> \(String(describing: newState)) (current=\(islandState))")
                if let newState = newState, newState != islandState {
                    withAnimation(ContactIslandAnimation.spring) {
                        islandState = newState
                    }
                }
            }
            .onChange(of: nameText) { _, newValue in
                guard isSearchActive && (isSearchFocused || isEditingName) else { return }
                let trimmed = newValue.trimmingCharacters(in: .whitespacesAndNewlines)
                let originalTrimmed = originalNameText.trimmingCharacters(in: .whitespacesAndNewlines)
                hasEditedName = trimmed != originalTrimmed
                if shouldTriggerContactSearch(for: newValue) {
                    triggerContactSearch(for: newValue)
                }
            }
            .onChange(of: islandState) { _, newState in
                print("🏝️ [IslandState] changed -> \(newState)")
                isDetentAnimating = true
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
                    isDetentAnimating = false
                }
                if newState == .compact {
                    allowSearchBlur = true
                    isSearchFocused = false
                }
                onStateChange?(newState)
            }
    }

    // MARK: - Presentation

    private var detentBinding: Binding<PresentationDetent> {
        Binding(
            get: {
                islandState == .compact ? cachedDetents.compact : fullSheetDetent
            },
            set: { newValue in
                islandState = newValue == cachedDetents.compact ? .compact : .fullSheet
            }
        )
    }

    private var fullSheetDetent: PresentationDetent {
        return .height(336)
    }

    private var activeFullDetentHeight: CGFloat {
        if isSearchFocused {
            return searchFocusedHeight
        }
        return isReviewMode ? reviewSheetHeight : viewSheetHeight
    }

    private var viewSheetHeight: CGFloat {
        min(screenHeight * 0.382, 320)
    }

    private var reviewSheetHeight: CGFloat {
        let reserved = DesignTokens.ContactIsland.controlsReservedHeight
        // On iPad, reduce reserved height to allow more content visibility
        let adjustedReserved = horizontalSizeClass == .regular ? reserved * 0.6 : reserved
        let height = screenHeight - adjustedReserved
        return max(DesignTokens.ContactIsland.compactHeight, height)
    }

    private var searchFocusedHeight: CGFloat {
        min(screenHeight * 0.382, 320)
    }

    private var isReviewMode: Bool {
        isSearchVisible || isEditingName
    }

    private struct FullScreenMetricsReader: UIViewRepresentable {
        let onChange: (CGFloat, UIEdgeInsets) -> Void

        func makeUIView(context: Context) -> UIView {
            let view = HeightReaderView()
            view.onHeightChange = onChange
            return view
        }

        func updateUIView(_ uiView: UIView, context: Context) {
            (uiView as? HeightReaderView)?.onHeightChange = onChange
            (uiView as? HeightReaderView)?.notifyHeightIfNeeded()
        }

        private final class HeightReaderView: UIView {
            var onHeightChange: ((CGFloat, UIEdgeInsets) -> Void)?
            private var lastHeight: CGFloat = 0
            private var lastInsets: UIEdgeInsets = .zero

            override func didMoveToWindow() {
                super.didMoveToWindow()
                notifyHeightIfNeeded()
            }

            override func layoutSubviews() {
                super.layoutSubviews()
                notifyHeightIfNeeded()
            }

            func notifyHeightIfNeeded() {
                guard let window else { return }
                let height = window.bounds.height
                let insets = window.safeAreaInsets
                guard height > 0 else { return }
                let heightChanged = abs(height - lastHeight) > 0.5
                let insetsChanged = insets != lastInsets
                guard heightChanged || insetsChanged else { return }
                lastHeight = height
                lastInsets = insets
                onHeightChange?(height, insets)
            }
        }
    }

    private func handleOnAppear() {
        print("🏝️ handleOnAppear: isOnboarding=\(isOnboarding), didInit=\(didInitializeOnboarding), initialState=\(initialState), externalPresent=\(externalState != nil)")
        let displayName = contactDisplayName
        let actualName = displayName == namePlaceholder ? "" : displayName
        nameText = actualName
        let service = ContactsSystemService()
        contactsPermissionStatus = service.authorizationStatus()
        syncMeetPlaceFromPhotoIfNeeded()

        // Start in full sheet for onboarding until a contact is selected
        if isOnboarding && !didInitializeOnboarding {
            didInitializeOnboarding = true
            let trimmed = (souvenir.primaryContact?.displayName ?? "")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            hasConfirmedSelection = !trimmed.isEmpty
            if !hasSelectedContact {
                islandState = .compact
                isEditingName = true
                allowSearchBlur = true
                isSearchFocused = false
                originalNameText = actualName
                hasEditedName = false
            } else {
                islandState = .fullSheet
            }
            print("🏝️ handleOnAppear: applied islandState=\(islandState)")
        } else if !didInitializeOnboarding {
            didInitializeOnboarding = true
            islandState = initialState
            print("🏝️ handleOnAppear: applied islandState=\(islandState)")
        }
    }

    private func expandToFullSheetIfNeeded() {
        guard isOnboarding, hasSelectedContact, !isEditingName else { return }
        guard islandState != .fullSheet else { return }
        withAnimation(ContactIslandAnimation.spring) {
            islandState = .fullSheet
        }
    }

    private func expandToFullSheetAndFocus(_ field: FocusField) {
        if islandState != .fullSheet {
            withAnimation(ContactIslandAnimation.spring) {
                islandState = .fullSheet
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                focusedField = field
            }
        } else {
            focusedField = field
        }
    }

    // MARK: - Island Content

    @ViewBuilder
    private func islandContent(activeState: ContactIslandState) -> some View {
        VStack(spacing: 0) {
            switch activeState {
            case .compact:
                compactContent
            case .fullSheet:
                fullSheetContent
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
    }

    // MARK: - Compact State

    private var compactContent: some View {
        VStack(alignment: .center, spacing: 0) {
            nameHeaderRow(font: .title)
            .offset(x: compactHorizontalOffset)
            .animation(ContactIslandAnimation.quickSpring, value: compactHorizontalOffset)
            .padding(.top, Tokens.Spacing.large)
            .padding(.horizontal, Tokens.Spacing.extraLarge)

            // Page indicator dots below name (compact only)
            if souvenirs.count > 1 {
                pageIndicator
                    .padding(.top, Tokens.Spacing.micro)
                    .padding(.bottom, Tokens.Spacing.medium)
            }
        }
        .contentShape(Rectangle())
        .gesture(
            DragGesture(minimumDistance: DesignTokens.Gesture.horizontalMinDistance)
                .onChanged { value in
                    let dx = value.translation.width
                    // Clamp to ±16pt for subtle feedback
                    let clamped = max(-16, min(16, dx))
                    compactHorizontalOffset = clamped
                }
                .onEnded { value in
                    withAnimation(ContactIslandAnimation.quickSpring) {
                        compactHorizontalOffset = 0
                    }
                    let dx = value.translation.width
                    let dy = value.translation.height
                    guard abs(dx) > abs(dy) else { return }
                    guard abs(dx) > DesignTokens.Gesture.dragThreshold else { return }
                    handleHorizontalSwipe(direction: dx < 0 ? 1 : -1)
                }
        )
    }

    /// Page indicator that caps at 5 dots with overflow indicator
    @ViewBuilder
    private var pageIndicator: some View {
        let totalCount = souvenirs.count
        let maxDots = 5
        let window = pageIndicatorWindow(totalCount: totalCount, maxDots: maxDots)
        let dotSize: CGFloat = 4
        let activeDotSize: CGFloat = 5
        let dotSpacing: CGFloat = 3

        HStack(spacing: dotSpacing) {
            if totalCount <= maxDots {
                // Show all dots
                ForEach(0..<totalCount, id: \.self) { index in
                    Circle()
                        .fill(index == currentSouvenirIndex ? Color.primary : Color.secondary.opacity(0.5))
                        .frame(
                            width: index == currentSouvenirIndex ? activeDotSize : dotSize,
                            height: index == currentSouvenirIndex ? activeDotSize : dotSize
                        )
                }
            } else {
                if window.start > 0 {
                    Text("•")
                        .font(.caption2)
                        .foregroundStyle(.secondary.opacity(0.5))
                }

                ForEach(window.start...window.end, id: \.self) { index in
                    Circle()
                        .fill(index == currentSouvenirIndex ? Color.primary : Color.secondary.opacity(0.5))
                        .frame(
                            width: index == currentSouvenirIndex ? activeDotSize : dotSize,
                            height: index == currentSouvenirIndex ? activeDotSize : dotSize
                        )
                }

                if window.end < totalCount - 1 {
                    Text("•")
                        .font(.caption2)
                        .foregroundStyle(.secondary.opacity(0.5))
                }
            }
        }
    }

    private var swipeIndicator: some View {
        HStack(spacing: Tokens.Spacing.micro) {
            Image(systemName: "chevron.left")
                .font(.caption2.weight(.semibold))
                .foregroundStyle(currentSouvenirIndex > 0 ? Color.primary : Color.primary.opacity(0.5))
            Spacer()
            pageIndicator
            Spacer()
            Image(systemName: "chevron.right")
                .font(.caption2.weight(.semibold))
                .foregroundStyle(currentSouvenirIndex < souvenirs.count - 1 ? Color.primary : Color.primary.opacity(0.5))
        }
        .padding(.vertical, Tokens.Spacing.micro) // TODO: layoutState == .compact ? 0 : Tokens.Spacing.micro
        .padding(.horizontal, Tokens.Spacing.large) // TODO: layoutState == .compact ? Tokens.Spacing.medium : Tokens.Spacing.large
        .frame(maxWidth: .infinity)
    }

    private func pageIndicatorWindow(totalCount: Int, maxDots: Int) -> (start: Int, end: Int) {
        if currentSouvenirIndex < 2 {
            return (0, maxDots - 1)
        } else if currentSouvenirIndex > totalCount - 3 {
            return (totalCount - maxDots, totalCount - 1)
        } else {
            return (currentSouvenirIndex - 2, currentSouvenirIndex + 2)
        }
    }

    private var isSearchActive: Bool {
        isOnboarding || isEditingName
    }

    private var isSearchVisible: Bool {
        isSearchActive && (isSearchFocused || isEditingName)
    }

    private var shouldShowConfirmButton: Bool {
        hasEditedName && !nameText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var isContactsAuthorized: Bool {
        if #available(iOS 17.0, *) {
            if contactsPermissionStatus == .limited {
                return false
            }
        }
        return contactsPermissionStatus == .authorized
    }

    private func openContactsSettings() {
        guard let url = URL(string: UIApplication.openSettingsURLString) else { return }
        UIApplication.shared.open(url, options: [:], completionHandler: nil)
    }

    @ViewBuilder
    private func applySearchBehavior<Content: View>(to content: Content, usesSearchable: Bool = true) -> some View {
        if isSearchVisible, usesSearchable {
            NavigationStack {
                content
                    .searchable(
                        text: $nameText,
                        placement: .navigationBarDrawer(displayMode: .always),
                        prompt: Text(namePlaceholder)
                    )
                    .searchFocused($isSearchFocused)
                    .textInputAutocapitalization(.words)
                    .autocorrectionDisabled()
                    .onChange(of: isSearchFocused) { _, focused in
                        if focused {
                            clearNameTextIfPlaceholder()
                        }
                    }
                    .onSubmit(of: .search) {
                        finishNameEditing()
                    }
                    .toolbar {
                        ToolbarItem(placement: .topBarTrailing) {
                            Button {
                                if shouldShowConfirmButton {
                                    finishNameEditing()
                                } else {
                                    cancelNameEditing()
                                }
                            } label: {
                                Image(systemName: shouldShowConfirmButton ? "checkmark" : "xmark")
                                    .font(.caption.weight(.semibold))
                                    .foregroundStyle(shouldShowConfirmButton ? Color.accentColor : Color.secondary)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                    .navigationTitle("")
                    .navigationBarTitleDisplayMode(.inline)
                    .toolbarBackground(.hidden, for: .navigationBar)
                    .background(Color.clear)
            }
            .scrollDisabled(islandState != .fullSheet)
            .background(Color.clear)
        } else {
            content
                .scrollDisabled(islandState != .fullSheet)
        }
    }

    @ViewBuilder
    private func searchResultsSection(limit: Int) -> some View {
        if isSearchActive && (isSearchFocused || isEditingName) {
            let trimmed = nameText.trimmingCharacters(in: .whitespacesAndNewlines)
            let displayed = Array(searchResults.prefix(limit))
            let canShowResults = isOnboarding || hasEditedName
            let hasQuery = canShowResults && !trimmed.isEmpty
            let resultsToShow = hasQuery ? displayed : []
            let showPrompt = !isContactsAuthorized && (isSearchFocused || isEditingName)

            SearchResults(
                resultsCount: resultsToShow.count,
                hasQuery: hasQuery,
                isSearching: isSearching && hasQuery,
                showPrompt: showPrompt,
                results: {
                    Section {
                        RoundedResultsCard {
                            ForEach(resultsToShow) { result in
                                VStack(spacing: 0) {
                                    contactResultRow(result)
                                    if result.id != resultsToShow.last?.id {
                                        Divider().padding(.leading, 40)
                                    }
                                }
                            }
                        }
                    }
                    .listRowBackground(Color.clear)
                    .listRowInsets(EdgeInsets(top: 2, leading: Tokens.Spacing.medium, bottom: 2, trailing: Tokens.Spacing.medium))
                    .listRowSeparator(.automatic)
                },
                empty: {
                    Section {
                        Text("No matches")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                    .listRowBackground(Color.clear)
                },
                loading: {
                    Section {
                        HStack {
                            Spacer()
                            ProgressView()
                            Spacer()
                        }
                    }
                    .listRowBackground(Color.clear)
                },

                prompt: {
                    Section {
                        Button {
                            if contactsPermissionStatus == .notDetermined {
                                presentContactsPrimer()
                            } else {
                                openContactsSettings()
                            }
                        } label: {
                            HStack {
                                Group {
                                    if contactsPermissionStatus == .notDetermined {
                                        Text("🧐 Search your contacts?")
                                            .font(.headline.weight(.medium))
                                            .foregroundStyle(.primary)
                                            .padding(.horizontal, Tokens.Spacing.large)
                                            .padding(.vertical, Tokens.Spacing.medium)
                                            .background(
                                                Capsule()
                                                    .fill(Color.warningSvnr.opacity(searchIndicatorPulse ? 0.22 : 0.12))
                                                    .shadow(color: Color.warningSvnr.opacity(searchIndicatorPulse ? 0.35 : 0.15), radius: searchIndicatorPulse ? 10 : 6, x: 0, y: 0)
                                            )
                                            .scaleEffect(searchIndicatorPulse ? 1.03 : 1.0)
                                            .animation(
                                                shouldAnimateSearchIndicator
                                                    ? .easeInOut(duration: 1.4).repeatForever(autoreverses: true)
                                                    : .default,
                                                value: searchIndicatorPulse
                                            )
                                            .onAppear {
                                                updateSearchIndicatorPulse()
                                            }
                                            .onChange(of: shouldAnimateSearchIndicator) { _, _ in
                                                updateSearchIndicatorPulse()
                                            }
                                    } else {
                                        Text("Enable Contacts in Settings")
                                            .font(.subheadline.weight(.medium))
                                            .foregroundStyle(.primary)
                                    }
                                }
                                Spacer()
                                if contactsPermissionStatus != .notDetermined {
                                    Image(systemName: "arrow.up.right.square")
                                        .font(.caption.weight(.semibold))
                                        .foregroundStyle(.secondary)
                                }
                            }
                        }
                        .buttonStyle(.plain)
                        .contentShape(Rectangle())
                        .padding(.horizontal, Tokens.Spacing.medium)
                        .padding(.vertical, Tokens.Spacing.small)
                    }
                    .listRowBackground(Color.winningSvnr.opacity(DesignTokens.Opacity.healthy))
                }
            )
        }
    }

