    private func openLocationSearchForMeetPlace() {
        guard let photo = currentPhoto else { return }
        // Onboarding: for fresh captures under 1 day old, apply current location and skip the map.
        if isRecentSouvenir && isRecentCapture {
            applyMeetPlaceFromCurrentLocation()
            return
        }

        if locationService.authorizationStatus == .notDetermined {
            locationService.requestPermission()
        }

        NotificationCenter.default.post(
            name: .svnrOpenLocationSearch,
            object: nil,
            userInfo: [
                "photoID": photo.id,
                "souvenirID": souvenir.id,
                "target": LocationSearchTarget.meetPlace.rawValue,
                "returnToNewSouvenir": isNewSouvenirFlow
            ]
        )
    }

    private func applyMeetPlaceFromCurrentLocation() {
        guard !isApplyingMeetPlace else { return }
        isApplyingMeetPlace = true
        let photoObjectID = currentPhoto?.objectID
        let souvenirObjectID = souvenir.objectID

        Task {
            await MainActor.run {
                if locationService.authorizationStatus == .notDetermined {
                    locationService.requestPermission()
                }
            }

            for _ in 0..<8 {
                let updated = await MainActor.run { locationService.authorizationStatus }
                if updated != .notDetermined {
                    break
                }
                try? await Task.sleep(for: .milliseconds(250))
            }

            let status = await MainActor.run { locationService.authorizationStatus }
            guard status == .authorizedWhenInUse || status == .authorizedAlways else {
                await MainActor.run { isApplyingMeetPlace = false }
                return
            }

            let currentLocation = await locationService.getCurrentLocation(timeout: 4.0)
            let cachedLocation = await MainActor.run { locationService.currentLocation }
            guard let location = currentLocation ?? cachedLocation else {
                await MainActor.run { isApplyingMeetPlace = false }
                return
            }

            let geocodingService = GeocodingService(persistenceController: PersistenceController.shared)
            let geocodedAddress = try? await geocodingService.reverseGeocode(
                latitude: location.coordinate.latitude,
                longitude: location.coordinate.longitude
            )

            await viewContext.perform {
                guard let souvenir = try? viewContext.existingObject(with: souvenirObjectID) as? SouvenirEntity else {
                    return
                }
                if let photoObjectID,
                   let photo = try? viewContext.existingObject(with: photoObjectID) as? PhotoEntity {
                    photo.latitude = NSNumber(value: location.coordinate.latitude)
                    photo.longitude = NSNumber(value: location.coordinate.longitude)
                    if let geocodedAddress = geocodedAddress {
                        photo.postalGeocodeJSON = geocodedAddress.toJSON()
                    }
                    if souvenir.meetTime == nil {
                        souvenir.meetTime = photo.timestamp ?? souvenir.createdAt
                    }
                }
                if let meetPlace = geocodedAddress?.shortDescription,
                   !meetPlace.isEmpty {
                    souvenir.meetPlace = meetPlace
                }
                if souvenir.meetTime == nil {
                    souvenir.meetTime = souvenir.createdAt
                }
                if viewContext.hasChanges {
                    try? viewContext.save()
                }
            }

            await MainActor.run {
                DerivationService.shared.didUpdatePhotos(for: souvenir.id)
                isApplyingMeetPlace = false
            }
        }
    }

