import SwiftUI
import CoreData
import Contacts
import CoreLocation
import UIKit
import MapKit

struct ContactIsland: View {
    @ObservedObject var souvenir: SouvenirEntity
    @Binding var currentSouvenirIndex: Int
    let souvenirs: [SouvenirEntity]
    var currentPhotoIndex: Int = 0
    var isOnboarding: Bool = false
    var isNewSouvenirFlow: Bool = false
    var initialState: ContactIslandState = .compact
    /// Binding for external state control (e.g., from map view)
    var externalState: Binding<ContactIslandState>?
    var onDismiss: (() -> Void)?
    /// Called when user taps save in onboarding mode
    var onSave: (() -> Void)?
    /// Called when island state changes (for parent coordination)
    var onStateChange: ((ContactIslandState) -> Void)?
    /// Called when user swipes up from fullSheet state (to navigate to souvenir detail)
    var onSwipeUpFromFullSheet: (() -> Void)?
    var isPreviewInline: Bool = false

    @Environment(\.managedObjectContext) private var viewContext
    @Environment(\.verticalSizeClass) private var verticalSizeClass
    @Environment(\.horizontalSizeClass) private var horizontalSizeClass

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: .default
    )
    private var selfContacts: FetchedResults<ContactEntity>

    @StateObject private var locationService = LocationService()
    @State private var screenHeight: CGFloat = 0
    @State private var safeAreaInsets: UIEdgeInsets = .zero
    @State private var isDetentAnimating = false
    @State private var islandState: ContactIslandState = .compact
    /// Memoizes detent calculations to prevent Observable churn from GeometryReader.onChange firing.
    /// Phase 2 fix: Replaces three computed detent properties with a single memoized calculator.
    @State private var detentCalc = DetentCalculator()
    // Memoize cachedDetents tuple in @State to prevent creating new tuple objects on every frame.
    // Updated via onChange(of: screenHeight) below. This breaks the feedback loop where computed
    // properties were creating new tuples → new Binding objects → Observable churn → corner loop.
    // Initialize with 0 to trigger DetentCalculator's guard clause (uses design token defaults).
    @State private var cachedDetents = DetentCalculator().detents(for: 0)
    @State private var didInitializeOnboarding: Bool = false
    @State private var showBirthdayPicker = false
    @State private var showBirthtimePicker = false
    @State private var showMeetTimePicker = false
    @State private var isApplyingMeetPlace = false
    @State private var showHomeCopiedToast = false
    @State private var homeToastTask: Task<Void, Never>?
    @State private var homeGeocodeTask: Task<Void, Never>?
    @State private var showRecentLocationSheet = false
    @State private var showBioSheet = false
    @State private var showRingsSheet = false
    @State private var nameText: String = ""
    @State private var isEditingName: Bool = false
    @State private var searchResults: [ContactSearchResult] = []
    @State private var searchTask: Task<Void, Never>?
    @State private var compactHorizontalOffset: CGFloat = 0
    private var isLandscape: Bool {
        verticalSizeClass == .compact
    }

    init(
        souvenir: SouvenirEntity,
        currentSouvenirIndex: Binding<Int>,
        souvenirs: [SouvenirEntity],
        currentPhotoIndex: Int = 0,
        isOnboarding: Bool = false,
        isNewSouvenirFlow: Bool = false,
        initialState: ContactIslandState = .compact,
        externalState: Binding<ContactIslandState>? = nil,
        onDismiss: (() -> Void)? = nil,
        onSave: (() -> Void)? = nil,
        onStateChange: ((ContactIslandState) -> Void)? = nil,
        onSwipeUpFromFullSheet: (() -> Void)? = nil,
        isPreviewInline: Bool = false
    ) {
        self.souvenir = souvenir
        self._currentSouvenirIndex = currentSouvenirIndex
        self.souvenirs = souvenirs
        self.currentPhotoIndex = currentPhotoIndex
        self.isOnboarding = isOnboarding
        self.isNewSouvenirFlow = isNewSouvenirFlow
        self.initialState = initialState
        self.externalState = externalState
        self.onDismiss = onDismiss
        self.onSave = onSave
        self.onStateChange = onStateChange
        self.onSwipeUpFromFullSheet = onSwipeUpFromFullSheet
        self.isPreviewInline = isPreviewInline
        // Removed ListAppearance.configureClearBackgrounds() 
        // UIKit appearance configuration should not be done during SwiftUI init
        // as it can cause observation tracking feedback loops
    }
    @State private var isSearching: Bool = false
    @State private var showZodiacPopover = false
    @State private var hasConfirmedSelection: Bool = false
    @State private var contactsPermissionStatus: CNAuthorizationStatus = .notDetermined
    @State private var showContactsPrimer = false
    @State private var showDeleteSouvenirConfirm = false
    @State private var searchIndicatorPulse = false
    @State private var originalNameText: String = ""
    @State private var hasEditedName: Bool = false
    @State private var dancePhase = false
    @State private var allowSearchBlur = false
    @FocusState private var focusedField: FocusField?
    @FocusState private var isSearchFocused: Bool
    private typealias Tokens = DesignTokens

    private enum FocusField: Hashable {
        case phone
        case email
        case address
    }

    var namePlaceholder: String = "Name, please"
    private var contactDisplayName: String {
        let display = souvenir.primaryContact?.displayName ?? ""
        let trimmed = display.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty { return namePlaceholder }
        if trimmed == "Unknown Contact" { return namePlaceholder }
        return display
    }

    private var placeholderNames: Set<String> {
        ["Name, please", "Name", "Unknown Contact"]
    }

    private var hasSelectedContact: Bool {
        if !isOnboarding { return true }
        return hasConfirmedSelection
    }

    private var currentPhone: String {
        let digits = normalizedPhoneDigits(from: souvenir.primaryContact?.phoneE164 ?? "")
        guard !digits.isEmpty else { return "" }
        if digits.first == "1" {
            return "+\(digits)"
        }
        return digits
    }

    private var currentEmail: String {
        souvenir.primaryContact?.email ?? ""
    }

    private var recentLocationText: String {
        if let location = currentPhoto?.locationString, !location.isEmpty {
            return location
        }
        if let meetPlace = souvenir.meetPlace, !meetPlace.isEmpty {
            return meetPlace
        }
        return "No recent location yet"
    }

    private var hasPhoneValue: Bool {
        !currentPhone.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var hasEmailValue: Bool {
        !currentEmail.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var currentPhoto: PhotoEntity? {
        let photos = souvenir.photosArray
        guard !photos.isEmpty else { return nil }
        if photos.indices.contains(currentPhotoIndex) {
            return photos[currentPhotoIndex]
        }
        return souvenir.favoritePhoto ?? photos.first
    }

    private var meetPlaceText: String {
        if let meetPlace = souvenir.meetPlace, !meetPlace.isEmpty {
            return meetPlace
        }
        if let locationString = currentPhoto?.locationString, !locationString.isEmpty {
            return locationString
        }
        if let lat = currentPhoto?.latitude?.doubleValue,
           let lon = currentPhoto?.longitude?.doubleValue,
           !(lat == 0.0 && lon == 0.0) {
            return String(format: "Locating... %.2f, %.2f", lat, lon)
        }
        return "📍 Add location"
    }

    private var needsMeetPlace: Bool {
        if let meetPlace = souvenir.meetPlace, !meetPlace.isEmpty {
            return false
        }
        guard let photo = currentPhoto else { return false }
        if let locationString = photo.locationString, !locationString.isEmpty {
            return false
        }
        if let lat = photo.latitude?.doubleValue,
           let lon = photo.longitude?.doubleValue,
           !(lat == 0.0 && lon == 0.0) {
            return false
        }
        return true
    }

