    /// The core presentation shell — detents, background, sheets, and confirmation dialog.
    /// Kept separate so the compiler doesn't have to type-check the entire modifier chain at once.
    private var islandBase: some View {
        baseContent
            // Sheets stay translucent only when the system background is cleared and we supply material via the presentation background.
            .background(Color.clear)
            .background {
                FullScreenMetricsReader { newHeight, newInsets in
                    let newKey = Int(newHeight.rounded())
                    let currentKey = Int(screenHeight.rounded())
                    guard newKey > 0 else { return }
                    guard newKey != currentKey || newInsets != safeAreaInsets else { return }
                    DispatchQueue.main.async {
                        let asyncKey = Int(screenHeight.rounded())
                        if newKey != asyncKey {
                            screenHeight = newHeight
                            print("🏝️ [Geo] full screen height: \(asyncKey) -> \(newKey)")
                        }
                        if newInsets != safeAreaInsets {
                            safeAreaInsets = newInsets
                        }
                    }
                }
            }
            .ignoresSafeArea()
            // Update cachedDetents when screenHeight changes. Only update when cache key actually
            // changes (rounding to integer) to avoid redundant state updates.
            .onChange(of: screenHeight) { oldHeight, newHeight in
                let oldKey = Int(oldHeight.rounded())
                let newKey = Int(newHeight.rounded())
                guard oldKey != newKey else { return }
                guard !isDetentAnimating else {
                    print("🏝️ [Detents] skipped during animation: \(oldKey) -> \(newKey)")
                    return
                }
                print("🏝️ [Detents] screenHeight changed: \(oldKey) -> \(newKey), islandState=\(islandState)")
                cachedDetents = detentCalc.detents(for: newHeight)
            }
            .presentationDetents(
                [cachedDetents.compact, fullSheetDetent],
                selection: detentBinding
            )
            .presentationDragIndicator(.visible)
            .presentationBackground(.clear)
            // Removed .presentationCornerRadius() - it causes observation tracking feedback loops
            // when combined with animated presentation detents. The system default corner radius
            // still provides a good visual appearance.
            .presentationBackgroundInteraction(.enabled)
            .interactiveDismissDisabled(true)
            .sheet(isPresented: $showBirthdayPicker) {
                birthdayPickerSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showBirthtimePicker) {
                birthtimePickerSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showMeetTimePicker) {
                meetTimePickerSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showContactsPrimer) {
                contactsPrimerSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showZodiacPopover) {
                zodiacSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showRecentLocationSheet) {
                recentLocationSheet
                    .presentationBackground(.clear)
                    .presentationBackgroundInteraction(.enabled)
            }
            .sheet(isPresented: $showBioSheet) {
