    /// All `.onChange`, `.onAppear`, and `.onReceive` modifiers grouped into two
    /// helpers so the compiler does not have to type-check the entire chain at once.
    private func lifecycleModifiers<V: View>(_ view: V) -> some View {
        lifecycleModifiersB(lifecycleModifiersA(view))
    }

    /// First half: data-driven `.onChange` modifiers.
    private func lifecycleModifiersA<V: View>(_ view: V) -> some View {
        view
            .onChange(of: contactDisplayName) { _, newValue in
                if !isEditingName {
                    nameText = newValue
                }
                expandToFullSheetIfNeeded()
            }
            .onChange(of: currentPhoto?.locationString ?? "") { _, _ in
                syncMeetPlaceFromPhotoIfNeeded()
            }
            .onChange(of: searchResults.count) { _, newCount in
                guard isOnboarding, isEditingName, isSearchFocused else { return }
                guard !nameText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return }
                guard newCount > 0 else { return }
                guard islandState != .fullSheet else { return }
                withAnimation(ContactIslandAnimation.spring) {
                    islandState = .fullSheet
                }
            }
            .onChange(of: isSearchFocused) { _, isFocused in
                if !isFocused {
                    // When editing, blurring should behave like tapping the trailing save/cancel button.
                    if isEditingName {
                        if shouldShowConfirmButton {
                            finishNameEditing()
                        } else {
                            cancelNameEditing()
                        }
                        return
                    }

                    if !allowSearchBlur {
                        isSearchFocused = true
                        return
                    }
                    allowSearchBlur = false
                    return
                }

                guard islandState != .fullSheet else { return }
                withAnimation(ContactIslandAnimation.spring) {
                    islandState = .fullSheet
                }
            }
    }

    /// Second half: appearance, notification, and state-sync modifiers.
    private func lifecycleModifiersB<V: View>(_ view: V) -> some View {
        view
            .onAppear {
                handleOnAppear()
            }
            .onReceive(NotificationCenter.default.publisher(for: .svnrFocusMeetTime)) { notification in
                guard let targetID = notification.userInfo?["souvenirID"] as? UUID else { return }
                guard targetID == souvenir.id else { return }
                openMeetTimePicker()
            }
            .onChange(of: externalState?.wrappedValue) { _, newState in
                print("🏝️ [ExternalState] -> \(String(describing: newState)) (current=\(islandState))")
                if let newState = newState, newState != islandState {
                    withAnimation(ContactIslandAnimation.spring) {
                        islandState = newState
                    }
                }
            }
            .onChange(of: nameText) { _, newValue in
                guard isSearchActive && (isSearchFocused || isEditingName) else { return }
                let trimmed = newValue.trimmingCharacters(in: .whitespacesAndNewlines)
                let originalTrimmed = originalNameText.trimmingCharacters(in: .whitespacesAndNewlines)
                hasEditedName = trimmed != originalTrimmed
                if shouldTriggerContactSearch(for: newValue) {
                    triggerContactSearch(for: newValue)
                }
            }
            .onChange(of: islandState) { _, newState in
                print("🏝️ [IslandState] changed -> \(newState)")
                isDetentAnimating = true
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
                    isDetentAnimating = false
                }
                if newState == .compact {
                    allowSearchBlur = true
                    isSearchFocused = false
                }
                onStateChange?(newState)
            }
    }

