    private struct FullScreenMetricsReader: UIViewRepresentable {
        let onChange: (CGFloat, UIEdgeInsets) -> Void

        func makeUIView(context: Context) -> UIView {
            let view = HeightReaderView()
            view.onHeightChange = onChange
            return view
        }

        func updateUIView(_ uiView: UIView, context: Context) {
            (uiView as? HeightReaderView)?.onHeightChange = onChange
            (uiView as? HeightReaderView)?.notifyHeightIfNeeded()
        }

        private final class HeightReaderView: UIView {
            var onHeightChange: ((CGFloat, UIEdgeInsets) -> Void)?
            private var lastHeight: CGFloat = 0
            private var lastInsets: UIEdgeInsets = .zero

            override func didMoveToWindow() {
                super.didMoveToWindow()
                notifyHeightIfNeeded()
            }

            override func layoutSubviews() {
                super.layoutSubviews()
                notifyHeightIfNeeded()
            }

            func notifyHeightIfNeeded() {
                guard let window else { return }
                let height = window.bounds.height
                let insets = window.safeAreaInsets
                guard height > 0 else { return }
                let heightChanged = abs(height - lastHeight) > 0.5
                let insetsChanged = insets != lastInsets
                guard heightChanged || insetsChanged else { return }
                lastHeight = height
                lastInsets = insets
                onHeightChange?(height, insets)
            }
        }
    }

    private func handleOnAppear() {
        print("🏝️ handleOnAppear: isOnboarding=\(isOnboarding), didInit=\(didInitializeOnboarding), initialState=\(initialState), externalPresent=\(externalState != nil)")
        let displayName = contactDisplayName
        let actualName = displayName == namePlaceholder ? "" : displayName
        nameText = actualName
        let service = ContactsSystemService()
        contactsPermissionStatus = service.authorizationStatus()
        syncMeetPlaceFromPhotoIfNeeded()

        // Start in full sheet for onboarding until a contact is selected
        if isOnboarding && !didInitializeOnboarding {
            didInitializeOnboarding = true
            let trimmed = (souvenir.primaryContact?.displayName ?? "")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            hasConfirmedSelection = !trimmed.isEmpty
            if !hasSelectedContact {
                islandState = .compact
                isEditingName = true
                allowSearchBlur = true
                isSearchFocused = false
                originalNameText = actualName
                hasEditedName = false
            } else {
                islandState = .fullSheet
            }
            print("🏝️ handleOnAppear: applied islandState=\(islandState)")
        } else if !didInitializeOnboarding {
            didInitializeOnboarding = true
            islandState = initialState
            print("🏝️ handleOnAppear: applied islandState=\(islandState)")
        }
    }

    private func expandToFullSheetIfNeeded() {
        guard isOnboarding, hasSelectedContact, !isEditingName else { return }
        guard islandState != .fullSheet else { return }
        withAnimation(ContactIslandAnimation.spring) {
            islandState = .fullSheet
        }
    }

    private func expandToFullSheetAndFocus(_ field: FocusField) {
        if islandState != .fullSheet {
            withAnimation(ContactIslandAnimation.spring) {
                islandState = .fullSheet
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.15) {
                focusedField = field
            }
        } else {
            focusedField = field
        }
    }

