    // MARK: - Compact State

    private var compactContent: some View {
        VStack(alignment: .center, spacing: 0) {
            nameHeaderRow(font: .title)
            .offset(x: compactHorizontalOffset)
            .animation(ContactIslandAnimation.quickSpring, value: compactHorizontalOffset)
            .padding(.top, Tokens.Spacing.large)
            .padding(.horizontal, Tokens.Spacing.extraLarge)

            // Page indicator dots below name (compact only)
            if souvenirs.count > 1 {
                pageIndicator
                    .padding(.top, Tokens.Spacing.micro)
                    .padding(.bottom, Tokens.Spacing.medium)
            }
        }
        .contentShape(Rectangle())
        .gesture(
            DragGesture(minimumDistance: DesignTokens.Gesture.horizontalMinDistance)
                .onChanged { value in
                    let dx = value.translation.width
                    // Clamp to ±16pt for subtle feedback
                    let clamped = max(-16, min(16, dx))
                    compactHorizontalOffset = clamped
                }
                .onEnded { value in
                    withAnimation(ContactIslandAnimation.quickSpring) {
                        compactHorizontalOffset = 0
                    }
                    let dx = value.translation.width
                    let dy = value.translation.height
                    guard abs(dx) > abs(dy) else { return }
                    guard abs(dx) > DesignTokens.Gesture.dragThreshold else { return }
                    handleHorizontalSwipe(direction: dx < 0 ? 1 : -1)
                }
        )
    }

    /// Page indicator that caps at 5 dots with overflow indicator
    @ViewBuilder
    private var pageIndicator: some View {
        let totalCount = souvenirs.count
        let maxDots = 5
        let window = pageIndicatorWindow(totalCount: totalCount, maxDots: maxDots)
        let dotSize: CGFloat = 4
        let activeDotSize: CGFloat = 5
        let dotSpacing: CGFloat = 3

        HStack(spacing: dotSpacing) {
            if totalCount <= maxDots {
                // Show all dots
                ForEach(0..<totalCount, id: \.self) { index in
                    Circle()
                        .fill(index == currentSouvenirIndex ? Color.primary : Color.secondary.opacity(0.5))
                        .frame(
                            width: index == currentSouvenirIndex ? activeDotSize : dotSize,
                            height: index == currentSouvenirIndex ? activeDotSize : dotSize
                        )
                }
            } else {
                if window.start > 0 {
                    Text("•")
                        .font(.caption2)
                        .foregroundStyle(.secondary.opacity(0.5))
                }

                ForEach(window.start...window.end, id: \.self) { index in
                    Circle()
                        .fill(index == currentSouvenirIndex ? Color.primary : Color.secondary.opacity(0.5))
                        .frame(
                            width: index == currentSouvenirIndex ? activeDotSize : dotSize,
                            height: index == currentSouvenirIndex ? activeDotSize : dotSize
                        )
                }

                if window.end < totalCount - 1 {
                    Text("•")
                        .font(.caption2)
                        .foregroundStyle(.secondary.opacity(0.5))
                }
            }
        }
    }

    private var swipeIndicator: some View {
        HStack(spacing: Tokens.Spacing.micro) {
            Image(systemName: "chevron.left")
                .font(.caption2.weight(.semibold))
                .foregroundStyle(currentSouvenirIndex > 0 ? Color.primary : Color.primary.opacity(0.5))
            Spacer()
            pageIndicator
            Spacer()
            Image(systemName: "chevron.right")
                .font(.caption2.weight(.semibold))
                .foregroundStyle(currentSouvenirIndex < souvenirs.count - 1 ? Color.primary : Color.primary.opacity(0.5))
        }
        .padding(.vertical, Tokens.Spacing.micro) // TODO: layoutState == .compact ? 0 : Tokens.Spacing.micro
        .padding(.horizontal, Tokens.Spacing.large) // TODO: layoutState == .compact ? Tokens.Spacing.medium : Tokens.Spacing.large
        .frame(maxWidth: .infinity)
    }

    private func pageIndicatorWindow(totalCount: Int, maxDots: Int) -> (start: Int, end: Int) {
        if currentSouvenirIndex < 2 {
            return (0, maxDots - 1)
        } else if currentSouvenirIndex > totalCount - 3 {
            return (totalCount - maxDots, totalCount - 1)
        } else {
            return (currentSouvenirIndex - 2, currentSouvenirIndex + 2)
        }
    }

