    @ViewBuilder
    private func applySearchBehavior<Content: View>(to content: Content, usesSearchable: Bool = true) -> some View {
        if isSearchVisible, usesSearchable {
            NavigationStack {
                content
                    .searchable(
                        text: $nameText,
                        placement: .navigationBarDrawer(displayMode: .always),
                        prompt: Text(namePlaceholder)
                    )
                    .searchFocused($isSearchFocused)
                    .textInputAutocapitalization(.words)
                    .autocorrectionDisabled()
                    .onChange(of: isSearchFocused) { _, focused in
                        if focused {
                            clearNameTextIfPlaceholder()
                        }
                    }
                    .onSubmit(of: .search) {
                        finishNameEditing()
                    }
                    .toolbar {
                        ToolbarItem(placement: .topBarTrailing) {
                            Button {
                                if shouldShowConfirmButton {
                                    finishNameEditing()
                                } else {
                                    cancelNameEditing()
                                }
                            } label: {
                                Image(systemName: shouldShowConfirmButton ? "checkmark" : "xmark")
                                    .font(.caption.weight(.semibold))
                                    .foregroundStyle(shouldShowConfirmButton ? Color.accentColor : Color.secondary)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                    .navigationTitle("")
                    .navigationBarTitleDisplayMode(.inline)
                    .toolbarBackground(.hidden, for: .navigationBar)
                    .background(Color.clear)
            }
            .scrollDisabled(islandState != .fullSheet)
            .background(Color.clear)
        } else {
            content
                .scrollDisabled(islandState != .fullSheet)
        }
    }

    @ViewBuilder
    private func searchResultsSection(limit: Int) -> some View {
        if isSearchActive && (isSearchFocused || isEditingName) {
            let trimmed = nameText.trimmingCharacters(in: .whitespacesAndNewlines)
            let displayed = Array(searchResults.prefix(limit))
            let canShowResults = isOnboarding || hasEditedName
            let hasQuery = canShowResults && !trimmed.isEmpty
            let resultsToShow = hasQuery ? displayed : []
            let showPrompt = !isContactsAuthorized && (isSearchFocused || isEditingName)

            SearchResults(
                resultsCount: resultsToShow.count,
                hasQuery: hasQuery,
                isSearching: isSearching && hasQuery,
                showPrompt: showPrompt,
                results: {
                    Section {
                        RoundedResultsCard {
                            ForEach(resultsToShow) { result in
                                VStack(spacing: 0) {
                                    contactResultRow(result)
                                    if result.id != resultsToShow.last?.id {
                                        Divider().padding(.leading, 40)
                                    }
                                }
                            }
                        }
                    }
                    .listRowBackground(Color.clear)
                    .listRowInsets(EdgeInsets(top: 2, leading: Tokens.Spacing.medium, bottom: 2, trailing: Tokens.Spacing.medium))
                    .listRowSeparator(.automatic)
                },
                empty: {
                    Section {
                        Text("No matches")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                    .listRowBackground(Color.clear)
                },
                loading: {
                    Section {
                        HStack {
                            Spacer()
                            ProgressView()
                            Spacer()
                        }
                    }
                    .listRowBackground(Color.clear)
                },

                prompt: {
                    Section {
                        Button {
                            if contactsPermissionStatus == .notDetermined {
                                presentContactsPrimer()
                            } else {
                                openContactsSettings()
                            }
                        } label: {
                            HStack {
                                Group {
                                    if contactsPermissionStatus == .notDetermined {
                                        Text("🧐 Search your contacts?")
                                            .font(.headline.weight(.medium))
                                            .foregroundStyle(.primary)
                                            .padding(.horizontal, Tokens.Spacing.large)
                                            .padding(.vertical, Tokens.Spacing.medium)
                                            .background(
                                                Capsule()
                                                    .fill(Color.warningSvnr.opacity(searchIndicatorPulse ? 0.22 : 0.12))
                                                    .shadow(color: Color.warningSvnr.opacity(searchIndicatorPulse ? 0.35 : 0.15), radius: searchIndicatorPulse ? 10 : 6, x: 0, y: 0)
                                            )
                                            .scaleEffect(searchIndicatorPulse ? 1.03 : 1.0)
                                            .animation(
                                                shouldAnimateSearchIndicator
                                                    ? .easeInOut(duration: 1.4).repeatForever(autoreverses: true)
                                                    : .default,
                                                value: searchIndicatorPulse
                                            )
                                            .onAppear {
                                                updateSearchIndicatorPulse()
                                            }
                                            .onChange(of: shouldAnimateSearchIndicator) { _, _ in
                                                updateSearchIndicatorPulse()
                                            }
                                    } else {
                                        Text("Enable Contacts in Settings")
                                            .font(.subheadline.weight(.medium))
                                            .foregroundStyle(.primary)
                                    }
                                }
                                Spacer()
                                if contactsPermissionStatus != .notDetermined {
                                    Image(systemName: "arrow.up.right.square")
                                        .font(.caption.weight(.semibold))
                                        .foregroundStyle(.secondary)
                                }
                            }
                        }
                        .buttonStyle(.plain)
                        .contentShape(Rectangle())
                        .padding(.horizontal, Tokens.Spacing.medium)
                        .padding(.vertical, Tokens.Spacing.small)
                    }
                    .listRowBackground(Color.winningSvnr.opacity(DesignTokens.Opacity.healthy))
                }
            )
        }
    }

