        }
    }

    private func finishNameEditing() {
        let trimmed = nameText.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmed.isEmpty {
            updateContactName(with: trimmed)
        } else {
            nameText = originalNameText
        }
        isEditingName = false
        searchResults = []
        allowSearchBlur = true
        isSearchFocused = false
        hasConfirmedSelection = !trimmed.isEmpty
        hasEditedName = false
        expandToFullSheetIfNeeded()
    }

    private func cancelNameEditing() {
        nameText = originalNameText
        isEditingName = false
        searchResults = []
        allowSearchBlur = true
        isSearchFocused = false
        hasEditedName = false
        expandToFullSheetIfNeeded()
    }

