    private func normalizedPhoneDigits(from input: String) -> String {
        let digits = input.filter(\.isNumber)
        guard !digits.isEmpty else { return "" }
        if digits.first == "1" {
            return String(digits.prefix(11))
        }
        return String(digits.prefix(10))
    }

    private func formattedPhone(_ input: String) -> String {
        let digits = normalizedPhoneDigits(from: input)
        guard !digits.isEmpty else { return "" }

        var rest = digits
        if rest.first == "1" {
            rest = String(rest.dropFirst())
        }

        let area = String(rest.prefix(3))
        let remainderAfterArea = String(rest.dropFirst(min(3, rest.count)))
        let prefix = String(remainderAfterArea.prefix(3))
        let line = String(remainderAfterArea.dropFirst(min(3, remainderAfterArea.count)).prefix(4))

        var result = ""
        if !area.isEmpty {
            if !result.isEmpty { result += " " }
            result += "(\(area)"
            if area.count == 3 { result += ")" }
        }

        if !prefix.isEmpty {
            if area.count == 3 { result += " " }
            result += prefix
        }

        if !line.isEmpty {
            result += "-\(line)"
        }

        return result
    }

