    private func updateContactName(with name: String) {
        guard let contact = ensureContact() else { return }
        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
        let parts = splitName(trimmed)
        viewContext.perform {
            contact.givenName = parts.given
            contact.familyName = parts.family
            contact.compositeName = trimmed
            souvenir.updatedAt = Date()
            try? viewContext.save()
        }
    }

    private func splitName(_ fullName: String) -> (given: String?, family: String?) {
        let parts = fullName
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .split(separator: " ")
            .map(String.init)
        guard !parts.isEmpty else { return (nil, nil) }
        if parts.count == 1 { return (parts[0], nil) }
        let family = parts.last
        let given = parts.dropLast().joined(separator: " ")
        return (given.isEmpty ? nil : given, family?.isEmpty == true ? nil : family)
    }

