    private func shouldTriggerContactSearch(for query: String) -> Bool {
        // Trigger search at 3+ characters with 250ms debounce (handled in triggerContactSearch)
        query.trimmingCharacters(in: .whitespacesAndNewlines).count >= 3
    }

    private func triggerContactSearch(for query: String) {
        searchTask?.cancel()
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            searchResults = []
            isSearching = false
            return
        }
        if trimmed.count < 2 {
            searchResults = []
            isSearching = false
            return
        }
        if contactsPermissionStatus == .notDetermined {
            if isOnboarding {
                isSearching = false
                return
            } else {
                showContactsPrimer = true
                isSearching = false
                return
            }
        }
        searchTask = Task {
            await MainActor.run { isSearching = true }
            try? await Task.sleep(for: .milliseconds(250))
            guard !Task.isCancelled else { return }
            await searchContacts(query: trimmed)
        }
    }

    private func searchContacts(query: String) async {
        guard !query.isEmpty else {
            await MainActor.run {
                searchResults = []
                isSearching = false
            }
            return
        }
        let service = ContactSearchService(persistenceController: .shared)
        let systemService = ContactsSystemService()
        let status = systemService.authorizationStatus()
        await MainActor.run { contactsPermissionStatus = status }
        let includeSystem = (status == .authorized)

        do {
            let results = try await service.searchAllContacts(query: query, includeSystem: includeSystem)
            await MainActor.run {
                searchResults = results
                isSearching = false
            }
        } catch {
            await MainActor.run {
                searchResults = []
                isSearching = false
            }
        }
    }

    private func handleContactSelection(_ result: ContactSearchResult) async {
        switch result {
        case .local(let contact):
            // If the local contact is missing fields (e.g., birthday), try to refresh from the system
            // contact using its externalIdentifier, then re-import (which backfills onto existing).
            if contact.birthday == nil,
               let externalIdentifier = contact.externalIdentifier {
                do {
                    let systemService = ContactsSystemService()
                    if systemService.authorizationStatus() == .authorized,
                       let cnContact = try await systemService.fetchContact(identifier: externalIdentifier) {
                        let service = ContactSearchService(persistenceController: .shared)
                        let refreshed = try await service.importSystemContact(cnContact)
                        await MainActor.run {
                            souvenir.primaryContact = refreshed
                            nameText = refreshed.displayName
                            isEditingName = false
                            searchResults = []
                            allowSearchBlur = true
                            isSearchFocused = false
                            hasConfirmedSelection = true
                            hasEditedName = false
                            expandToFullSheetIfNeeded()
                        }
                        return
                    }
                } catch {
                    // Fall back to using the local record as-is.
                }
            }
            if contact.birthday == nil,
               contact.externalIdentifier == nil {
                do {
                    let systemService = ContactsSystemService()
                    if systemService.authorizationStatus() == .authorized {
                        let query = contact.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
                        if !query.isEmpty {
                            let candidates = try await systemService.searchContacts(query: query)
                            let targetPhone = (contact.phoneE164 ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                            let targetEmail = (contact.email ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
                            let match = candidates.first { candidate in
                                if !targetEmail.isEmpty, candidate.emailAddresses.contains(where: { ($0.value as String).caseInsensitiveCompare(targetEmail) == .orderedSame }) {
                                    return true
                                }
                                if !targetPhone.isEmpty {
                                    let normalizer = ContactSearchNormalizer()
                                    return candidate.phoneNumbers.contains(where: { normalizer.normalizePhone(input: $0.value.stringValue) == targetPhone })
                                }
                                return false
                            } ?? candidates.first
                            if let match {
                                let service = ContactSearchService(persistenceController: .shared)
                                let refreshed = try await service.importSystemContact(match)
                                await MainActor.run {
                                    souvenir.primaryContact = refreshed
                                    nameText = refreshed.displayName
                                    isEditingName = false
                                    searchResults = []
                                    allowSearchBlur = true
                                    isSearchFocused = false
                                    hasConfirmedSelection = true
                                    hasEditedName = false
                                    expandToFullSheetIfNeeded()
                                }
                                return
                            }
                        }
                    }
                } catch {
                    // Fall back to local record.
                }
            }
            await MainActor.run {
                souvenir.primaryContact = contact
                nameText = contact.displayName
                isEditingName = false
                searchResults = []
                allowSearchBlur = true
                isSearchFocused = false
                hasConfirmedSelection = true
                hasEditedName = false
                expandToFullSheetIfNeeded()
            }
        case .system(let cnContact):
            do {
                let service = ContactSearchService(persistenceController: .shared)
                let imported = try await service.importSystemContact(cnContact)
                await MainActor.run {
                    souvenir.primaryContact = imported
                    nameText = imported.displayName
                    isEditingName = false
                    searchResults = []
                    allowSearchBlur = true
                    isSearchFocused = false
                    hasConfirmedSelection = true
                    hasEditedName = false
                    expandToFullSheetIfNeeded()
                }
            } catch {
                print("⚠️ Failed to import contact: \(error.localizedDescription)")

                // Debug: Print detailed contact info that failed
                print("🔍 Contact details that failed:")
                print("   Given Name: '" + cnContact.givenName + "'")
                print("   Family Name: '" + cnContact.familyName + "'")
                print("   Phone Numbers: ", cnContact.phoneNumbers.map { $0.value.stringValue })
                print("   Email Addresses: ", cnContact.emailAddresses.map { $0.value as String })

                // Handle specific validation errors
                if let validationError = error as? ValidationError {
                    print("📋 Specific validation error: ", validationError.errorDescription ?? "Unknown")
                    print("💡 Recovery suggestion: ", validationError.recoverySuggestion ?? "None")

                    await MainActor.run {
                        searchResults = []
                        nameText = ""
                        isEditingName = true

                        // Show user-friendly error message
                        let errorMessage = validationError.errorDescription ?? "Invalid contact data"
                        let suggestion = validationError.recoverySuggestion ?? ""
                        let fullMessage = suggestion.isEmpty ? errorMessage : "\(errorMessage). \(suggestion)"

                        // For now, just re-enable editing. In future, could show toast/alert
                        print("📝 User feedback: ", fullMessage)
                    }
                } else {
                    // Handle other types of errors
                    await MainActor.run {
                        searchResults = []
                        nameText = ""
                        isEditingName = true
                    }
                }
            }
        case .new(let name):
            await MainActor.run {
                nameText = name
                updateContactName(with: name)
                isEditingName = false
                searchResults = []
                allowSearchBlur = true
                isSearchFocused = false
                hasConfirmedSelection = true
                hasEditedName = false
                expandToFullSheetIfNeeded()
            }
        }
    }
}

