private struct ContactIslandPreview: View {
    let initialState: ContactIslandState
    @State private var currentIndex: Int = 0

    var body: some View {
        let context = PersistenceController.preview.container.viewContext
        let request: NSFetchRequest<SouvenirEntity> = {
            let request = SouvenirEntity.fetchRequest()
            request.fetchLimit = 3
            return request
        }()

        if let souvenirs = try? context.fetch(request), let first = souvenirs.first {
            ZStack {
                // Simulated photo background
                LinearGradient(
                    colors: [.blue.opacity(0.3), .purple.opacity(0.3)],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
                .ignoresSafeArea()
            }
            .sheet(isPresented: .constant(true)) {
                ContactIslandPreviewContent(
                    souvenir: first,
                    souvenirs: Array(souvenirs),
                    initialState: initialState,
                    currentIndex: $currentIndex
                )
            }
            .environment(\.managedObjectContext, context)
        } else {
            Text("No preview data")
        }
    }
}

