import CoreData
import SwiftUI

struct SvnrHybridView: View {
    @EnvironmentObject private var router: Router
    @Environment(\.managedObjectContext) private var viewContext
    @Environment(\.displayScale) private var displayScale
    @Environment(\.horizontalSizeClass) private var horizontalSizeClass
    @Binding var viewMode: MainViewMode
    let transitionNamespace: Namespace.ID

    @AppStorage("favoriteSouvenirID") private var favoriteSouvenirIDString: String = ""
    @AppStorage("svnrHasSavedFirstSouvenir") private var hasSavedFirstSouvenir = false

    // Timeline mode data
    @FetchRequest(
        sortDescriptors: [NSSortDescriptor(keyPath: \SouvenirEntity.updatedAt, ascending: false)],
        predicate: NSCompoundPredicate(andPredicateWithSubpredicates: [
            SouvenirEntity.activePredicate,
            NSPredicate(format: "photos.@count > 0 AND primaryContact != nil AND (primaryContact.compositeName != nil AND primaryContact.compositeName != '' OR primaryContact.givenName != nil AND primaryContact.givenName != '')")
        ]),
        animation: nil
    )
    private var souvenirs: FetchedResults<SouvenirEntity>

    // Rings mode: self's bonds whose contact has a souvenir, sorted by manual ring order.
    @FetchRequest(
        sortDescriptors: [NSSortDescriptor(keyPath: \BondEntity.ringOrder, ascending: true)],
        predicate: NSPredicate(format: "owner.isSelf == YES AND contact.primarySouvenir != nil"),
        animation: nil
    )
    private var bonds: FetchedResults<BondEntity>

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: nil
    )
    private var selfContacts: FetchedResults<ContactEntity>

    @State private var favoriteBackgroundImage: UIImage?
    @State private var favoriteBackgroundAssetId: String?
    @State private var showAmbientGlyphLineTrace: Bool = true

    private let photoLoader = PhotoLoadingService()

    // MARK: - Computed lists

    @MainActor
    private var sortedSouvenirs: [SouvenirEntity] {
        souvenirs.sorted(by: SouvenirEntity.byFrecencyDescending)
    }

    private var selfContact: ContactEntity? { selfContacts.first }

    private var orderedBonds: [BondEntity] {
        bonds.sorted { $0.ringOrder < $1.ringOrder }
    }

    // MARK: - Body

    var body: some View {
        GeometryReader { geometry in
            ZStack {
                BackgroundView(image: favoriteBackgroundImage)

                if viewMode == .timeline && sortedSouvenirs.isEmpty {
                    SouvenirOnboardingIntroView(onAddPhotos: startOnboardingCamera)
                        .ignoresSafeArea()
                } else if viewMode == .rings && orderedBonds.isEmpty {
                    RingsEmptyState()
                } else {
                    listContent
                }
            }
            .onAppear {
                loadFavoriteBackground(screenSize: geometry.size)
                if !sortedSouvenirs.isEmpty {
                    hasSavedFirstSouvenir = true
                }
            }
            .onChange(of: favoriteSouvenirIDString) { _, _ in
                loadFavoriteBackground(screenSize: geometry.size)
            }
            .onChange(of: sortedSouvenirs.count) { _, newValue in
                if newValue > 0 {
                    hasSavedFirstSouvenir = true
                }
            }
        }
        .svnrNavigationStyle()
    }

    // MARK: - List content

    @ViewBuilder
    private var listContent: some View {
        List {
            if viewMode == .rings {
                ForEach(orderedBonds, id: \.objectID) { bond in
                    if let souvenir = bond.contact?.primarySouvenir {
                        SouvenirCapsuleView(
                            souvenir: souvenir,
                            onSelect: { router.navigate(to: .souvenir(id: souvenir.id)) },
                            transitionNamespace: transitionNamespace
                        )
                        .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
                        .listRowBackground(Color.clear)
                        .listRowSeparator(.hidden)
                        .swipeActions(edge: .trailing, allowsFullSwipe: false) {
                            if let contactID = bond.contact?.id {
                                Button {
                                    router.navigate(to: .contactRings(contactID: contactID))
                                } label: {
                                    Label("View Tree", systemImage: "arrow.trianglehead.branch")
                                }
                                .tint(.accent)
                            }
                        }
                    }
                }
                .onMove(perform: moveBonds)
            } else {
                ForEach(sortedSouvenirs, id: \.id) { souvenir in
                    timelineRow(for: souvenir)
                        .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
                        .listRowBackground(Color.clear)
                        .listRowSeparator(.hidden)
                        .swipeActions(edge: .trailing, allowsFullSwipe: false) {
                            if let contactID = souvenir.primaryContact?.id {
                                Button {
                                    router.navigate(to: .contactRings(contactID: contactID))
                                } label: {
                                    Label("View Tree", systemImage: "arrow.trianglehead.branch")
                                }
                                .tint(.accent)
                            }
                        }
                }

                // Trailing add-placeholder
                AddSouvenirCapsuleView()
                    .listRowInsets(EdgeInsets(top: 6, leading: 16, bottom: 6, trailing: 16))
                    .listRowBackground(Color.clear)
                    .listRowSeparator(.hidden)
                    .opacity(0.7)

                // Ambient glyph footer
                AmbientGlyph(
                    size: 120,
                    animated: true,
                    showLineTrace: showAmbientGlyphLineTrace,
                    onGlyphTap: {
                        withAnimation(.easeInOut(duration: 0.2)) {
                            showAmbientGlyphLineTrace.toggle()
                        }
                    }
                )
                .padding(.vertical, DesignTokens.Spacing.jumbo)
                .listRowInsets(.init())
                .listRowBackground(Color.clear)
                .listRowSeparator(.hidden)
                .frame(maxWidth: .infinity)
            }
        }
        .listStyle(.plain)
        .scrollContentBackground(.hidden)
        // Edit mode always active so drag handles appear in rings mode;
        // swipe actions work in both modes regardless of edit mode state.
        .environment(\.editMode, .constant(.active))
    }

    // MARK: - Row builders

    @ViewBuilder
    private func timelineRow(for souvenir: SouvenirEntity) -> some View {
        SouvenirCapsuleView(
            souvenir: souvenir,
            onSelect: {
                router.navigate(to: .souvenir(id: souvenir.id))
            },
            transitionNamespace: transitionNamespace
        )
    }

    @ViewBuilder
    private func ringsRow(for contact: ContactEntity) -> some View {
        if let souvenir = contact.primarySouvenir {
            SouvenirCapsuleView(
                souvenir: souvenir,
                onSelect: {
                    router.navigate(to: .souvenir(id: souvenir.id))
                },
                transitionNamespace: transitionNamespace
            )
        } else {
            HybridPlaceholderRow(contact: contact)
                .contentShape(Rectangle())
                .onTapGesture {
                    selectedConnection = contact
                    showConnectionSheet = true
                }
        }
    }

    // MARK: - Drag-to-reorder (rings mode)

    private func moveBonds(from source: IndexSet, to destination: Int) {
        guard let owner = selfContact else { return }
        let service = RingOrderService(viewContext: viewContext, owner: owner)
        var mutable = orderedBonds
        mutable.move(fromOffsets: source, toOffset: destination)
        do {
            service.applyOrderedBonds(mutable)
            try viewContext.save()
        } catch {
            print("❌ SvnrHybridView: failed to reorder bond: \(error)")
        }
    }

    // MARK: - Background loading

    private func loadFavoriteBackground(screenSize: CGSize) {
        guard let id = UUID(uuidString: favoriteSouvenirIDString) else {
            favoriteBackgroundImage = nil
            favoriteBackgroundAssetId = nil
            SvnrPaletteStore.reset()
            return
        }
        guard let souvenir = fetchSouvenir(id: id),
              let assetId = souvenir.favoritePhoto?.assetLocalId else {
            favoriteBackgroundImage = nil
            favoriteBackgroundAssetId = nil
            SvnrPaletteStore.reset()
            return
        }
        guard assetId != favoriteBackgroundAssetId else { return }
        favoriteBackgroundAssetId = assetId
        Task {
            let image = await photoLoader.loadPhoto(assetLocalId: assetId)
            await MainActor.run {
                favoriteBackgroundImage = image
            }
            if let image,
               let accent = await ColorExtractionService.shared.extractDominantColor(from: image) {
                let palette = SvnrPalette.derive(from: accent)
                SvnrPaletteStore.setPalette(palette)
            }
            logBackgroundImage(image, assetId: assetId, screenSize: screenSize, scale: displayScale)
        }
    }

    private func logBackgroundImage(_ image: UIImage?, assetId: String, screenSize: CGSize, scale: CGFloat) {
        let requiredWidth = screenSize.width * scale
        let requiredHeight = screenSize.height * scale
        if let image {
            let imageWidth = image.size.width * image.scale
            let imageHeight = image.size.height * image.scale
            let suitable = imageWidth >= requiredWidth && imageHeight >= requiredHeight
            print("🖼️ Hybrid background [\(assetId)] size: \(Int(imageWidth))x\(Int(imageHeight)) px | required: \(Int(requiredWidth))x\(Int(requiredHeight)) | suitable: \(suitable)")
        } else {
            print("🖼️ Hybrid background [\(assetId)] failed to load; defaulting to svnr-surf.")
        }
    }

    private func startOnboardingCamera() {
        NotificationCenter.default.post(name: .svnrRequestCamera, object: nil)
    }

    private func fetchSouvenir(id: UUID) -> SouvenirEntity? {
        let request: NSFetchRequest<SouvenirEntity> = SouvenirEntity.fetchRequest()
        request.fetchLimit = 1
        request.predicate = NSCompoundPredicate(andPredicateWithSubpredicates: [
            SouvenirEntity.activePredicate,
            NSPredicate(format: "id == %@", id as CVarArg)
        ])
        return try? viewContext.fetch(request).first
    }
}

