   222→    private func moveBonds(from source: IndexSet, to destination: Int) {
   223→        guard let owner = selfContact else { return }
   224→        let service = RingOrderService(viewContext: viewContext, owner: owner)
   225→        var mutable = orderedBonds
   226→        mutable.move(fromOffsets: source, toOffset: destination)
   227→        do {
   228→            service.applyOrderedBonds(mutable)
   229→            try viewContext.save()
   230→        } catch {
   231→            print("❌ SvnrHybridView: failed to reorder bond: \(error)")
   232→        }
   233→    }
