   235→    // MARK: - Background loading
   236→
   237→    private func loadFavoriteBackground(screenSize: CGSize) {
   238→        guard let id = UUID(uuidString: favoriteSouvenirIDString) else {
   239→            favoriteBackgroundImage = nil
   240→            favoriteBackgroundAssetId = nil
   241→            SvnrPaletteStore.reset()
   242→            return
   243→        }
   244→        guard let souvenir = fetchSouvenir(id: id),
   245→              let assetId = souvenir.favoritePhoto?.assetLocalId else {
   246→            favoriteBackgroundImage = nil
   247→            favoriteBackgroundAssetId = nil
   248→            SvnrPaletteStore.reset()
   249→            return
   250→        }
   251→        guard assetId != favoriteBackgroundAssetId else { return }
   252→        favoriteBackgroundAssetId = assetId
   253→        Task {
   254→            let image = await photoLoader.loadPhoto(assetLocalId: assetId)
   255→            await MainActor.run {
   256→                favoriteBackgroundImage = image
   257→            }
   258→            if let image,
   259→               let accent = await ColorExtractionService.shared.extractDominantColor(from: image) {
   260→                let palette = SvnrPalette.derive(from: accent)
   261→                SvnrPaletteStore.setPalette(palette)
   262→            }
   263→            logBackgroundImage(image, assetId: assetId, screenSize: screenSize, scale: displayScale)
   264→        }
   265→    }
   266→
   267→    private func logBackgroundImage(_ image: UIImage?, assetId: String, screenSize: CGSize, scale: CGFloat) {
   268→        let requiredWidth = screenSize.width * scale
   269→        let requiredHeight = screenSize.height * scale
   270→        if let image {
   271→            let imageWidth = image.size.width * image.scale
   272→            let imageHeight = image.size.height * image.scale
   273→            let suitable = imageWidth >= requiredWidth && imageHeight >= requiredHeight
   274→            print("🖼️ Hybrid background [\(assetId)] size: \(Int(imageWidth))x\(Int(imageHeight)) px | required: \(Int(requiredWidth))x\(Int(requiredHeight)) | suitable: \(suitable)")
   275→        } else {
   276→            print("🖼️ Hybrid background [\(assetId)] failed to load; defaulting to svnr-surf.")
   277→        }
   278→    }
