   284→    private func fetchSouvenir(id: UUID) -> SouvenirEntity? {
   285→        let request: NSFetchRequest<SouvenirEntity> = SouvenirEntity.fetchRequest()
   286→        request.fetchLimit = 1
   287→        request.predicate = NSCompoundPredicate(andPredicateWithSubpredicates: [
   288→            SouvenirEntity.activePredicate,
   289→            NSPredicate(format: "id == %@", id as CVarArg)
   290→        ])
   291→        return try? viewContext.fetch(request).first
   292→    }
   293→}
