     4→/// Compact capsule preview for a single souvenir.
     5→struct SouvenirCapsuleView: View {
     6→    let souvenir: SouvenirEntity
     7→    let onSelect: () -> Void
     8→    let onAddLocation: ((PhotoEntity) -> Void)? = nil
     9→    var transitionNamespace: Namespace.ID? = nil
    10→    let capsuleHeight: CGFloat = 300
    11→    let capsuleWidth: CGFloat = 360
    12→
    13→    private let photoRatio: CGFloat = 6.0 / 5.0
    14→    @Environment(\.colorScheme) private var colorScheme
    15→
    16→    private var highlightPhoto: PhotoEntity? {
    17→        souvenir.favoritePhoto ?? souvenir.latestPhoto
    18→    }
    19→
    20→    private var contactName: String {
    21→        let name = souvenir.primaryContact?.displayName ?? ""
    22→        let trimmed = name.trimmingCharacters(in: .whitespacesAndNewlines)
    23→        if trimmed.isEmpty || trimmed == "Unknown" {
    24→            return "Name"
    25→        }
    26→        return name
    27→    }
    28→
    29→    private var locationText: String {
    30→        if let meetPlace = souvenir.meetPlace?.trimmingCharacters(in: .whitespacesAndNewlines),
    31→           !meetPlace.isEmpty {
    32→            return meetPlace
    33→        }
    34→        // Determine location text with fallback hierarchy:
    35→        // 1. Use geocoded location string if available
    36→        // 2. Fall back to raw coordinates if photo has them
    37→        // 3. Only show "Add location" if no coordinates exist
    38→        if let locationString = highlightPhoto?.locationString {
    39→            return locationString
    40→        }
    41→        if let photo = highlightPhoto,
    42→           let lat = photo.latitude?.doubleValue,
    43→           let lon = photo.longitude?.doubleValue,
    44→           !(lat == 0.0 && lon == 0.0) {
    45→            return String(format: "%.2f, %.2f", lat, lon)
    46→        }
    47→        return "📍 Add location"
    48→    }
    49→
    50→    private var dateText: String {
    51→        if let meetTime = souvenir.meetTime {
    52→            return DateFormatters.relativeString(from: meetTime)
