    79→    private func formatPhoneNumber(_ number: String) -> String {
    80→        let digits = number.filter { $0.isNumber }
    81→        guard !digits.isEmpty else { return "" }
    82→
    83→        if digits.count <= 3 {
    84→            return digits
    85→        } else if digits.count <= 6 {
    86→            return "(\(digits.prefix(3))) \(digits.dropFirst(3))"
    87→        } else {
    88→            let areaCode = digits.prefix(3)
    89→            let exchange = digits.dropFirst(3).prefix(3)
    90→            let lineNumber = digits.dropFirst(6).prefix(4)
    91→            return "(\(areaCode)) \(exchange)-\(lineNumber)"
    92→        }
    93→    }
    94→}
